macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

fn solve() {
    let (a, x, y) = parse_line!(i64, i64, i64);
    if y <= 0 || y % a == 0 || x.abs() >= a {
        return println!("-1");
    }
    if y < a {
        if (x * 2).abs() < a {
            println!("1");
        }else{
            println!("-1");
        }
        return;
    }
    let y = y - a;
    let period = y / (2 * a);
    let left = y % (2 * a);
    if left < a {
        if (x * 2).abs() < a {
            println!("{}", 2 + period * 3);
        }else{
            println!("-1");
        }
    }else{
        if x < 0 {
            println!("{}", 3 + period * 3);
        }else if x > 0 {
            println!("{}", 4 + period * 3);
        }else{
            println!("-1");
        }
    }
}

fn main() {
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve();
    }
}
